import React from 'react';
import { Link, useLocation } from 'react-router-dom';
import { useTranslation } from 'react-i18next';

const BottomNavigation = () => {
  const { t } = useTranslation();
  const location = useLocation();

  // Restore icons for navigation
  const { 
    HiHome, 
    HiOutlineClipboardList, 
    HiOutlineCalendar, 
    HiOutlineUser, 
    HiOutlineCog 
  } = require('react-icons/hi');

  const navItems = [
    { path: '/', label: t('home'), icon: HiHome },
    { path: '/medicines', label: t('medicines'), icon: HiOutlineClipboardList },
    { path: '/availability', label: t('availability'), icon: HiOutlineCalendar },
    { path: '/profile', label: t('profile'), icon: HiOutlineUser },
    { path: '/settings', label: t('settings'), icon: HiOutlineCog }
  ];

  return (
    <nav 
      className="fixed bottom-0 left-0 right-0 bg-white/95 backdrop-blur-lg border-t border-gray-200 shadow-2xl"
      style={{
        position: 'fixed',
        bottom: '0',
        left: '0',
        right: '0',
        zIndex: '50',
        backgroundColor: 'rgba(255, 255, 255, 0.95)',
        borderTop: '1px solid #e5e7eb',
        boxShadow: '0 -8px 32px rgba(0, 0, 0, 0.1)',
        backdropFilter: 'blur(16px)'
      }}
      role="navigation"
      aria-label="Main navigation"
    >
      {/* Top gradient line */}
      <div className="absolute top-0 left-0 right-0 h-0.5 bg-gradient-to-r from-blue-500 via-purple-500 to-green-500"></div>
      
      <div className="flex justify-between items-center h-16 px-2 pb-[env(safe-area-inset-bottom,0px)]">
        {navItems.map((item) => {
          const Icon = item.icon;
          const isActive = location.pathname === item.path;
          
          return (
            <Link
              key={item.path}
              to={item.path}
              className={`flex flex-col items-center justify-center py-2 px-3 no-underline min-w-0 flex-1 rounded-2xl transition-all duration-300 transform ${
                isActive 
                  ? 'bg-gradient-to-r from-blue-50 to-indigo-50 border border-blue-200 scale-105' 
                  : 'hover:bg-gray-50 hover:scale-105'
              }`}
              style={{ textDecoration: 'none' }}
              aria-label={`Navigate to ${item.label}`}
            >
              <div className={`relative p-1 rounded-xl transition-all duration-300 ${
                isActive ? 'bg-gradient-to-r from-blue-500 to-indigo-600 shadow-lg' : ''
              }`}>
                <Icon className={`text-lg transition-colors duration-300 ${
                  isActive ? 'text-white' : 'text-gray-600 hover:text-blue-500'
                }`} />
                {isActive && (
                  <div className="absolute inset-0 rounded-xl bg-white/20 animate-pulse"></div>
                )}
              </div>
              <span
                className={`text-[10px] mt-1 leading-tight font-medium transition-colors duration-300 ${
                  isActive ? 'text-blue-700 font-bold' : 'text-gray-600'
                }`}
              >
                {item.label}
              </span>
              {isActive && (
                <div className="absolute bottom-0 left-1/2 transform -translate-x-1/2 w-1 h-1 bg-blue-500 rounded-full"></div>
              )}
            </Link>
          );
        })}
      </div>
    </nav>
  );
};

export default BottomNavigation;
